      "content": "const _ = require('lodash');
const data = require('../../data/problems.json');

/**
 * Get problems filtered by difficulty, tags, and limited by count.
 * @param {Object} params
 * @param {string|string[]} [params.tags] - Skill tags to filter by (case-insensitive, comma-separated string or array).
 * @param {string} [params.difficulty] - Difficulty filter (exact match).
 * @param {number} [params.limit] - Maximum number of problems to return.
 * @returns {Object} - { metadata: { tags: string[] }, results: Array }
 */
function getProblems({ tags, difficulty, limit } = {}) {
  let problems = data.problems || [];

  // Normalize tags filter to array of lowercase strings
  let filterTags = [];
  if (tags) {
    if (Array.isArray(tags)) {
      filterTags = tags.map(t => t.toLowerCase());
    } else if (typeof tags === 'string') {
      filterTags = tags.split(',').map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
    }
  }

  // Filter by difficulty if provided
  if (difficulty) {
    problems = problems.filter(p => p.difficulty === difficulty);
  }

  // Filter by tags if provided
  if (filterTags.length > 0) {
    problems = problems.filter(p => {
      if (!p.tags || !Array.isArray(p.tags)) return false;
      const problemTagsLower = p.tags.map(t => t.toLowerCase());
      // Check if problemTagsLower contains all filterTags
      return filterTags.every(ft => problemTagsLower.includes(ft));
    });
  }

  // Sort problems by stable criteria: difficulty asc, then problemId asc
  problems = _.orderBy(problems, ['difficulty', 'problemId'], ['asc', 'asc']);

  // Apply limit if provided
  if (limit && Number.isInteger(limit) && limit > 0) {
    problems = problems.slice(0, limit);
  }

  // Compose metadata with normalized tags filter
  const metadata = {
    tags: filterTags
  };

  return {
    metadata,
    results: problems
  };
}

module.exports = {
  getProblems
};
